import { useRef, useState, useEffect } from 'react'
import { useParams } from 'react-router-dom'
import html2canvas from 'html2canvas'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const mockupRef = useRef(null)

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const presetBoxes = {

    front: {
      x: 50,
      y: 36,
      width: 195,
      height: 240,
      zoom: 100
    },

    'left-chest': {
      x: 42,
      y: 28,
      width: 72,
      height: 72,
      zoom: 100
    },

    back: {
      x: 50,
      y: 35,
      width: 210,
      height: 255,
      zoom: 100
    }
  }

  const [selectedColor, setSelectedColor] =
    useState(product.colors[0])

  const [uploadedLogo, setUploadedLogo] =
    useState(null)

  const [logoWidth, setLogoWidth] =
    useState(
      presetBoxes.front.width
    )

  const [logoHeight, setLogoHeight] =
    useState(
      presetBoxes.front.height
    )

  const [originalImageSize, setOriginalImageSize] =
    useState({
      width: 1,
      height: 1
    })

  const [logoScale, setLogoScale] =
    useState(100)

  const [logoWarp, setLogoWarp] =
    useState(0)

  const [logoRotation, setLogoRotation] =
    useState(0)

  const [activePreset, setActivePreset] =
    useState('front')

  const [dragEnabled, setDragEnabled] =
    useState(false)

  const [customPosition, setCustomPosition] =
    useState({
      x: presetBoxes.front.x,
      y: presetBoxes.front.y
    })

  const [boxWidth, setBoxWidth] =
    useState(
      presetBoxes.front.width
    )

  const [boxHeight, setBoxHeight] =
    useState(
      presetBoxes.front.height
    )

  const [isDragging, setIsDragging] =
    useState(false)

  const [resizeDirection, setResizeDirection] =
    useState(null)

  const autoFitLogo = (
    imageWidth,
    imageHeight,
    areaWidth,
    areaHeight
  ) => {

    const imageRatio =
      imageWidth / imageHeight

    const areaRatio =
      areaWidth / areaHeight

    let width
    let height

    if (imageRatio > areaRatio) {

      width = areaWidth

      height =
        areaWidth / imageRatio

    } else {

      height = areaHeight

      width =
        areaHeight * imageRatio
    }

    return {
      width,
      height
    }
  }

  useEffect(() => {

    if (!uploadedLogo) return

    const fitted =
      autoFitLogo(
        originalImageSize.width,
        originalImageSize.height,
        boxWidth,
        boxHeight
      )

    setLogoWidth(
      fitted.width
    )

    setLogoHeight(
      fitted.height
    )

  }, [
    boxWidth,
    boxHeight,
    activePreset
  ])

  const handleUpload = (e) => {

    const file =
      e.target.files[0]

    if (!file) return

    const imageUrl =
      URL.createObjectURL(file)

    const img = new Image()

    img.onload = () => {

      setOriginalImageSize({
        width: img.width,
        height: img.height
      })

      const fitted =
        autoFitLogo(
          img.width,
          img.height,
          boxWidth,
          boxHeight
        )

      setLogoWidth(
        fitted.width
      )

      setLogoHeight(
        fitted.height
      )

      setUploadedLogo(
        imageUrl
      )
    }

    img.src = imageUrl
  }

  const setPreset = (type) => {

    setActivePreset(type)

    const box =
      presetBoxes[type]

    setCustomPosition({
      x: box.x,
      y: box.y
    })

    setBoxWidth(
      box.width
    )

    setBoxHeight(
      box.height
    )

    setLogoScale(
      box.zoom
    )
  }

  const removeLogo = () => {

    setUploadedLogo(null)
  }

  const exportMockup = async () => {

    const canvas =
      await html2canvas(
        mockupRef.current,
        {
          backgroundColor: null,
          scale: 3,
          useCORS: true,
          width:
            mockupRef.current.offsetWidth,
          height:
            mockupRef.current.offsetHeight
        }
      )

    const image =
      canvas.toDataURL(
        'image/png'
      )

    const link =
      document.createElement(
        'a'
      )

    link.href = image

    link.download =
      `mockup-${activePreset}.png`

    link.click()
  }

  const handleMouseMove = (e) => {

    const rect =
      e.currentTarget.getBoundingClientRect()

    if (
      dragEnabled &&
      isDragging
    ) {

      const x =
        (
          (
            e.clientX -
            rect.left
          ) /
          rect.width
        ) * 100

      const y =
        (
          (
            e.clientY -
            rect.top
          ) /
          rect.height
        ) * 100

      const limitedX =
        Math.max(
          10,
          Math.min(90, x)
        )

      const limitedY =
        Math.max(
          10,
          Math.min(90, y)
        )

      setCustomPosition({
        x: limitedX,
        y: limitedY
      })
    }

    if (resizeDirection) {

      const movementX =
        e.movementX

      const movementY =
        e.movementY

      let newWidth =
        boxWidth

      let newHeight =
        boxHeight

      if (
        resizeDirection ===
        'bottom-right'
      ) {

        newWidth =
          boxWidth + movementX

        newHeight =
          boxHeight + movementY
      }

      if (
        resizeDirection ===
        'bottom-left'
      ) {

        newWidth =
          boxWidth - movementX

        newHeight =
          boxHeight + movementY
      }

      if (
        resizeDirection ===
        'top-right'
      ) {

        newWidth =
          boxWidth + movementX

        newHeight =
          boxHeight - movementY
      }

      if (
        resizeDirection ===
        'top-left'
      ) {

        newWidth =
          boxWidth - movementX

        newHeight =
          boxHeight - movementY
      }

      newWidth =
        Math.max(
          40,
          Math.min(
            420,
            newWidth
          )
        )

      newHeight =
        Math.max(
          40,
          Math.min(
            420,
            newHeight
          )
        )

      setBoxWidth(
        newWidth
      )

      setBoxHeight(
        newHeight
      )
    }
  }

  const stopActions = () => {

    setIsDragging(false)

    setResizeDirection(null)
  }

  const centerHorizontally = () => {

    setCustomPosition(prev => ({
      ...prev,
      x: 50
    }))
  }

  const centerVertically = () => {

    setCustomPosition(prev => ({
      ...prev,
      y: 50
    }))
  }

  return (

    <div
      className="h-screen bg-black text-white overflow-hidden"
      onMouseMove={
        handleMouseMove
      }
      onMouseUp={
        stopActions
      }
    >

      <div className="grid grid-cols-1 xl:grid-cols-[65%_35%] h-full">

        <div
          ref={mockupRef}
          id="mockup-area"
          className="bg-[#e9e9e9] flex items-center justify-center relative p-10 w-full h-full overflow-hidden"
        >

          <img
            src={
              activePreset ===
              'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[700px] max-h-[88vh] object-contain"
          />

          {uploadedLogo && (

            <div
              className={`absolute flex items-center justify-center border-2 border-red-500 ${
                dragEnabled
                  ? 'cursor-move'
                  : ''
              }`}
              style={{
                width:
                  `${boxWidth}px`,
                height:
                  `${boxHeight}px`,
                top:
                  `${customPosition.y}%`,
                left:
                  `${customPosition.x}%`,
                transform:
                  'translate(-50%, -50%)'
              }}
              onMouseDown={() => {

                if (
                  dragEnabled
                ) {
                  setIsDragging(true)
                }
              }}
            >

              <img
                src={uploadedLogo}
                alt="logo"
                className="select-none pointer-events-none"
                style={{
                  width:
                    `${logoWidth}px`,
                  height:
                    `${logoHeight}px`,
                  objectFit:
                    'contain',
                  maxWidth: '100%',
                  maxHeight: '100%',
                  transform: `
                    scale(${logoScale / 100})
                    perspective(900px)
                    rotateX(${logoWarp}deg)
                    rotate(${logoRotation}deg)
                  `
                }}
                draggable={false}
              />

            </div>

          )}

        </div>

        <div className="bg-black border-l border-[#1d1d1d] flex flex-col h-full overflow-y-auto">

          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

          </div>

          <div className="p-6 space-y-6">

            <div>

              <h2 className="text-sm font-black mb-4">
                Shirt Colors
              </h2>

              <div className="grid grid-cols-2 gap-3">

                {product.colors.map(
                  (color) => (

                  <button
                    key={color.name}
                    onClick={() =>
                      setSelectedColor(
                        color
                      )
                    }
                    className={`p-4 rounded-xl text-xs font-black capitalize ${
                      selectedColor.name ===
                      color.name
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {color.name}
                  </button>

                ))}

              </div>

            </div>

            <div>

              <h2 className="text-sm font-black mb-4">
                Placement
              </h2>

              <div className="grid grid-cols-1 gap-3">

                {[
                  'front',
                  'left-chest',
                  'back'
                ].map((item) => (

                  <button
                    key={item}
                    onClick={() =>
                      setPreset(item)
                    }
                    className={`p-4 rounded-xl text-xs font-black ${
                      activePreset ===
                      item
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {item}
                  </button>

                ))}

              </div>

            </div>

            <div className="grid grid-cols-2 gap-3">

              <button
                onClick={
                  centerHorizontally
                }
                className="bg-[#111] border border-[#222] py-4 rounded-xl text-xs font-black"
              >
                CENTER X
              </button>

              <button
                onClick={
                  centerVertically
                }
                className="bg-[#111] border border-[#222] py-4 rounded-xl text-xs font-black"
              >
                CENTER Y
              </button>

            </div>

            <div>

              <button
                onClick={() =>
                  setDragEnabled(
                    !dragEnabled
                  )
                }
                className={`w-full py-4 rounded-xl text-xs font-black ${
                  dragEnabled
                    ? 'bg-yellow-500 text-black'
                    : 'bg-[#111] border border-[#222]'
                }`}
              >
                {dragEnabled
                  ? 'DRAG MODE ON'
                  : 'DRAG MODE OFF'}
              </button>

            </div>

            <div>

              <h2 className="text-sm font-black mb-4">
                Upload Logo
              </h2>

              <input
                type="file"
                accept="image/png,image/jpeg"
                onChange={
                  handleUpload
                }
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-sm"
              />

            </div>

            {uploadedLogo && (

              <>

                <button
                  onClick={
                    removeLogo
                  }
                  className="w-full border border-red-500 text-red-500 py-4 rounded-xl text-xs font-black"
                >

                  REMOVE LOGO

                </button>

                <button
                  onClick={
                    exportMockup
                  }
                  className="w-full bg-white text-black py-4 rounded-xl text-xs font-black"
                >

                  EXPORT MOCKUP

                </button>

                <div>

                  <div className="flex justify-between mb-3">

                    <p className="text-xs text-white/60">
                      Zoom
                    </p>

                    <p className="text-xs text-yellow-500 font-black">
                      {logoScale}%
                    </p>

                  </div>

                  <input
                    type="range"
                    min="50"
                    max="180"
                    value={logoScale}
                    onChange={(e) =>
                      setLogoScale(
                        e.target.value
                      )
                    }
                    className="w-full"
                  />

                </div>

                <div>

                  <div className="flex justify-between mb-3">

                    <p className="text-xs text-white/60">
                      Rotation
                    </p>

                    <p className="text-xs text-yellow-500 font-black">
                      {logoRotation}°
                    </p>

                  </div>

                  <input
                    type="range"
                    min="-180"
                    max="180"
                    value={logoRotation}
                    onChange={(e) =>
                      setLogoRotation(
                        e.target.value
                      )
                    }
                    className="w-full"
                  />

                </div>

                <div>

                  <div className="flex justify-between mb-3">

                    <p className="text-xs text-white/60">
                      Fabric Warp
                    </p>

                    <p className="text-xs text-yellow-500 font-black">
                      {logoWarp}°
                    </p>

                  </div>

                  <input
                    type="range"
                    min="-20"
                    max="20"
                    value={logoWarp}
                    onChange={(e) =>
                      setLogoWarp(
                        e.target.value
                      )
                    }
                    className="w-full"
                  />

                </div>

              </>

            )}

          </div>

        </div>

      </div>

    </div>

  )
}
